import{_ as t,o as r,c as l,a2 as o}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Rana Plaza 大楼坍塌（2013）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/cases/csr/rana-plaza.md","filePath":"zh/cases/csr/rana-plaza.md"}'),n={name:"zh/cases/csr/rana-plaza.md"};function e(i,a,s,d,h,c){return r(),l("div",null,[...a[0]||(a[0]=[o('<h1 id="rana-plaza-大楼坍塌-2013" tabindex="-1">Rana Plaza 大楼坍塌（2013） <a class="header-anchor" href="#rana-plaza-大楼坍塌-2013" aria-label="Permalink to &quot;Rana Plaza 大楼坍塌（2013）&quot;">​</a></h1><p><strong>快时尚供应链的最高代价</strong></p><blockquote><p><strong>关联指南：</strong> <a href="/zh/csr-guide.html">企业社会责任审核指南</a> · <strong>适用行业：</strong> 服装、纺织、鞋类</p></blockquote><hr><h2 id="事件经过" tabindex="-1">事件经过 <a class="header-anchor" href="#事件经过" aria-label="Permalink to &quot;事件经过&quot;">​</a></h2><p>2013年4月24日，孟加拉国达卡郊区的 Rana Plaza 商业综合楼轰然倒塌，造成<strong>1,134人死亡、2,500余人受伤</strong>，是人类历史上伤亡最惨重的工业事故之一。</p><p>大楼共八层，其中五至八层为服装工厂，为 Primark、Benetton、Mango、Walmart 等欧美品牌加工服装。事发前一天，大楼已出现明显裂缝，银行等商业租户已宣布停业疏散，但工厂管理者以&quot;赶订单&quot;为由，<strong>强迫工人返岗上班</strong>，并威胁不上班者扣薪。次日清晨，大楼在工人上班后数小时内整体垮塌。</p><h3 id="结构性原因" tabindex="-1">结构性原因 <a class="header-anchor" href="#结构性原因" aria-label="Permalink to &quot;结构性原因&quot;">​</a></h3><ul><li>大楼原批准用途为商业/零售，<strong>未经许可擅自加盖四层</strong>作为工厂</li><li>大楼建设使用了劣质材料，设计承重远不足以支撑重型工业设备</li><li>数台大型发电机（工厂自备电源）安装于顶层，振动加速了结构疲劳</li></ul><hr><h2 id="供应链审核的失败" tabindex="-1">供应链审核的失败 <a class="header-anchor" href="#供应链审核的失败" aria-label="Permalink to &quot;供应链审核的失败&quot;">​</a></h2><p>Rana Plaza 揭示了当时&quot;合规审核&quot;体系的系统性缺陷：</p><table tabindex="0"><thead><tr><th>失败环节</th><th>具体表现</th></tr></thead><tbody><tr><td><strong>分包隐瞒</strong></td><td>品牌采购商只知道一级供应商，工厂秘密将订单转包至 Rana Plaza，未经披露</td></tr><tr><td><strong>审核频率不足</strong></td><td>多数品牌每年仅审核一次，且提前告知，工厂有充裕时间&quot;布景&quot;</td></tr><tr><td><strong>建筑安全盲区</strong></td><td>审核清单聚焦劳工标准（加班、工资），<strong>从不检查建筑结构安全</strong></td></tr><tr><td><strong>审核员技能局限</strong></td><td>SA8000、BSCI等社会审核员没有工程背景，无法识别结构风险</td></tr><tr><td><strong>买方压力传导</strong></td><td>极短的交期与极低的采购价迫使工厂压缩成本，包括安全投入</td></tr></tbody></table><hr><h2 id="后续响应" tabindex="-1">后续响应 <a class="header-anchor" href="#后续响应" aria-label="Permalink to &quot;后续响应&quot;">​</a></h2><h3 id="孟加拉国《服装业协议》-accord-on-fire-and-building-safety" tabindex="-1">孟加拉国《服装业协议》（Accord on Fire and Building Safety） <a class="header-anchor" href="#孟加拉国《服装业协议》-accord-on-fire-and-building-safety" aria-label="Permalink to &quot;孟加拉国《服装业协议》（Accord on Fire and Building Safety）&quot;">​</a></h3><p>事故发生后数周，220余个品牌签署了由工会主导的**《孟加拉国消防与建筑安全协议》**（Accord），核心条款：</p><ul><li>委托独立工程师对工厂进行<strong>建筑、电气、消防</strong>三项专项检查</li><li>检查结果<strong>公开披露</strong>（品牌无权隐瞒不合格工厂）</li><li>品牌承诺为整改提供<strong>资金支持</strong>（不能以&quot;供应商费用&quot;转嫁工厂）</li><li>设立工人<strong>投诉热线</strong>，举报无须担心被解雇</li></ul><p>截至2018年，Accord 覆盖超过1,600家工厂，发现并整改了10万余项安全隐患。</p><h3 id="rana-plaza-赔偿基金" tabindex="-1">Rana Plaza 赔偿基金 <a class="header-anchor" href="#rana-plaza-赔偿基金" aria-label="Permalink to &quot;Rana Plaza 赔偿基金&quot;">​</a></h3><p>国际劳工组织（ILO）主导设立赔偿基金，最终募集约3,000万美元。Primark 等品牌个别捐款，但大量品牌在初期<strong>拒绝承认在该楼采购</strong>，以逃避赔偿责任，品牌声誉受到严重冲击。</p><hr><h2 id="对审核实践的启示" tabindex="-1">对审核实践的启示 <a class="header-anchor" href="#对审核实践的启示" aria-label="Permalink to &quot;对审核实践的启示&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">审核人员应特别关注</p><p><strong>建筑安全检查须成为标准环节：</strong></p><ul><li>核查建筑使用许可证与实际用途是否一致</li><li>查看是否有超出批准层数的违规加建</li><li>重型设备（发电机、空调机组）安装是否有结构评估报告</li></ul><p><strong>分包管控须列入合同条款：</strong></p><ul><li>供应商合同须明确&quot;未经书面批准不得分包&quot;</li><li>定期抽查订单实际生产地点（可通过布料卷标、缝制标签追溯）</li><li>要求供应商披露所有二级加工厂并纳入审核范围</li></ul><p><strong>工人声音渠道：</strong></p><ul><li>撤销品牌LOGO等标识，以匿名方式开展工人访谈</li><li>设立独立举报渠道（不通过工厂管理层转达）</li><li>询问&quot;如果今天上班有安全顾虑，你有权拒绝吗？&quot;</li></ul></div><hr><h2 id="延伸阅读" tabindex="-1">延伸阅读 <a class="header-anchor" href="#延伸阅读" aria-label="Permalink to &quot;延伸阅读&quot;">​</a></h2><ul><li>ILO: <em>Rana Plaza — 5 years on</em> (2018)</li><li>Clean Clothes Campaign: <em>Voices from the Rubble</em></li><li>Business &amp; Human Rights Resource Centre: <em>Rana Plaza brand tracker</em></li><li>Bangladesh Accord on Fire and Building Safety: <a href="https://bangladeshaccord.org" target="_blank" rel="noreferrer">bangladeshaccord.org</a></li><li>Labowitz &amp; Baumann-Pauly (NYU Stern): <em>Business as Usual is Not an Option</em> (2014)</li></ul>',27)])])}const p=t(n,[["render",e]]);export{g as __pageData,p as default};
